/* ============================================================
   PHOTACC front-end — shared by index.html (voter) and admin.html
   Talks to the Express server: /api/vote, /api/check-email, /api/admin/results
   ============================================================ */

const IMAGES = {
  logo:     "data:image/png;base64,",
  brandon:  "data:image/jpeg;base64,",
  miah:     "data:image/jpeg;base64,",
  brittany: "data:image/jpeg;base64,",
  calisa:   "data:image/jpeg;base64,",
};

const CANDIDATES = [
  { id:"brandon",  name:"Brandon",  role:"Event Officer",     slogan:"We plan the moments you'll never forget.", pos:"center 22%" },
  { id:"miah",     name:"Miah",     role:"Technical Officer", slogan:"Technology behind every great shot.",       pos:"center 18%" },
  { id:"brittany", name:"Brittany", role:"PRO",               slogan:"We promote the moments you capture them.",  pos:"center 16%" },
  { id:"calisa",   name:"Calisa",   role:"President",         slogan:"Leading today. Inspiring tomorrow.",        pos:"center 16%" },
];

const $  = (s)=>document.querySelector(s);
const $$ = (s)=>document.querySelectorAll(s);
const isReal = (s)=>typeof s==="string" && s.startsWith("data:");
const initial = (n)=>n.trim().charAt(0).toUpperCase();
const validEmail = (e)=>/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);

let voterEmail = "", choices = {}, adminPassword = "";

/* ---------- shared ---------- */
function applyBranding(){
  ["#brandMark","#heroLogo","#footLogo"].forEach(sel=>{
    const el=$(sel); if(!el) return;
    if(isReal(IMAGES.logo)){ el.style.backgroundImage=`url('${IMAGES.logo}')`; }
    else { el.style.background="radial-gradient(circle at 35% 30%,#1c1c25,#08080a)"; el.style.display="grid"; el.style.placeItems="center"; el.style.color="var(--gold)"; el.style.fontFamily="'Cormorant Garamond',serif"; el.style.fontWeight="700"; el.textContent="P"; }
  });
}
function showScreen(id){
  $$(".screen").forEach(s=>s.classList.remove("screen--active"));
  const el=document.getElementById(id); if(el) el.classList.add("screen--active");
  window.scrollTo({top:0,behavior:"smooth"});
}

/* ---------- ambient gold bokeh ---------- */
function startBokeh(){
  const canvas=$("#bokeh"); if(!canvas) return;
  const ctx=canvas.getContext("2d"); let w,h;
  function size(){ const dpr=Math.min(2,window.devicePixelRatio||1); w=canvas.width=innerWidth*dpr; h=canvas.height=innerHeight*dpr; ctx.setTransform(dpr,0,0,dpr,0,0); }
  size(); addEventListener("resize",size);
  const dots=Array.from({length:26},()=>({ x:Math.random()*innerWidth, y:Math.random()*innerHeight, r:8+Math.random()*30, a:.04+Math.random()*.12, vy:-(.08+Math.random()*.25), vx:(Math.random()-.5)*.1, tw:Math.random()*Math.PI*2 }));
  (function loop(){
    ctx.clearRect(0,0,innerWidth,innerHeight);
    for(const d of dots){
      d.y+=d.vy; d.x+=d.vx; d.tw+=.02;
      if(d.y< -40){ d.y=innerHeight+40; d.x=Math.random()*innerWidth; }
      const a=d.a*(.6+.4*Math.sin(d.tw));
      const g=ctx.createRadialGradient(d.x,d.y,0,d.x,d.y,d.r);
      g.addColorStop(0,`rgba(241,221,149,${a})`); g.addColorStop(1,"rgba(241,221,149,0)");
      ctx.fillStyle=g; ctx.beginPath(); ctx.arc(d.x,d.y,d.r,0,Math.PI*2); ctx.fill();
    }
    requestAnimationFrame(loop);
  })();
}

/* ---------- voter page ---------- */
function renderShowcase(){
  $("#showcase").innerHTML = CANDIDATES.map(c=>`
    <figure class="figure">
      <div class="figure__frame">
        <span class="vf vf--tl"></span><span class="vf vf--tr"></span><span class="vf vf--bl"></span><span class="vf vf--br"></span>
        <div class="figure__portrait" style="${isReal(IMAGES[c.id])?`background-image:url('${IMAGES[c.id]}');background-position:${c.pos}`:""}">
          ${isReal(IMAGES[c.id])?"":`<div style="height:100%;display:grid;place-items:center;font-family:'Cormorant Garamond',serif;font-size:64px;color:var(--gold-deep)">${initial(c.name)}</div>`}
        </div>
      </div>
      <div class="figure__plate">
        <h3 class="figure__name">${c.name.toUpperCase()}</h3>
        <p class="figure__role">${c.role}</p>
        <span class="figure__rule"></span>
        <p class="figure__quote">"${c.slogan}"</p>
      </div>
    </figure>`).join("");
}

function renderBallot(){
  const list=$("#ballotList");
  list.innerHTML = CANDIDATES.map(c=>`
    <li class="ballot__row" data-id="${c.id}">
      <div class="ballot__photo" style="${isReal(IMAGES[c.id])?`background-image:url('${IMAGES[c.id]}')`:""}">${isReal(IMAGES[c.id])?"":`<div style="height:100%;display:grid;place-items:center;font-family:'Cormorant Garamond',serif;color:var(--gold-deep)">${initial(c.name)}</div>`}</div>
      <div class="ballot__meta"><p class="ballot__name">${c.name}</p><p class="ballot__role">${c.role}</p></div>
      <div class="ballot__choices">
        <button class="choice choice--yes" data-id="${c.id}" data-val="yes">Yes</button>
        <button class="choice choice--no" data-id="${c.id}" data-val="no">No</button>
      </div>
    </li>`).join("");
  list.querySelectorAll(".choice").forEach(btn=>{
    btn.addEventListener("click",()=>{
      const {id,val}=btn.dataset; choices[id]=val;
      const row=list.querySelector(`.ballot__row[data-id="${id}"]`);
      row.setAttribute("data-answered",val);
      row.querySelectorAll(".choice").forEach(b=>b.classList.remove("is-on"));
      btn.classList.add("is-on"); updateProgress();
    });
  });
}
function updateProgress(){
  const decided=CANDIDATES.filter(c=>choices[c.id]).length;
  $("#ballotProgress").textContent=`${decided} of ${CANDIDATES.length} decided`;
  $("#submitVote").disabled = decided!==CANDIDATES.length;
  if(decided===CANDIDATES.length) $("#ballotError").textContent="";
}
function startVote(){ voterEmail=""; $("#emailInput").value=""; $("#emailError").textContent=""; showScreen("email"); setTimeout(()=>$("#emailInput").focus(),350); }

async function continueFromEmail(){
  const email=$("#emailInput").value.trim().toLowerCase(), err=$("#emailError"); err.textContent="";
  if(!validEmail(email)){ err.textContent="Enter a valid email address to receive your ballot."; return; }
  try{
    const r=await fetch(`/api/check-email?email=${encodeURIComponent(email)}`);
    if(r.ok){ const d=await r.json(); if(d.voted){ err.textContent="This email has already voted. Each email gets one ballot."; return; } }
  }catch(_){ /* non-blocking */ }
  voterEmail=email; choices={}; renderBallot(); updateProgress(); showScreen("ballot");
}

async function submitVote(){
  const err=$("#ballotError"); err.textContent="";
  if(CANDIDATES.some(c=>!choices[c.id])){ err.textContent="Please choose Yes or No for all four candidates."; return; }
  $("#submitVote").disabled=true;
  try{
    const r=await fetch("/api/vote",{ method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({email:voterEmail,choices}) });
    const d=await r.json().catch(()=>({}));
    if(r.ok){ lockIn(); }
    else if(r.status===409){ err.textContent=d.error||"This email has already voted."; $("#submitVote").disabled=false; }
    else { err.textContent=d.error||"Something went wrong. Please try again."; $("#submitVote").disabled=false; }
  }catch(_){ err.textContent="Could not reach the server. Check your connection and try again."; $("#submitVote").disabled=false; }
}

function lockIn(){
  const fl=$("#flash"); if(fl){ fl.classList.remove("pop"); void fl.offsetWidth; fl.classList.add("pop"); }
  $("#lockedStamp").textContent=new Date().toLocaleString();
  setTimeout(()=>{ showScreen("locked"); fireConfetti(); },240);
}

function fireConfetti(){
  const canvas=$("#confetti"); if(!canvas) return;
  const ctx=canvas.getContext("2d"); canvas.style.display="block";
  const dpr=window.devicePixelRatio||1; canvas.width=innerWidth*dpr; canvas.height=innerHeight*dpr; ctx.scale(dpr,dpr);
  const colors=["#d8b54a","#f1dd95","#9a7a26","#f6f1e4","#fff3cf"];
  const pieces=Array.from({length:180},()=>({ x:innerWidth/2+(Math.random()-.5)*140, y:innerHeight/2.4, vx:(Math.random()-.5)*15, vy:Math.random()*-17-6, g:.32+Math.random()*.15, size:5+Math.random()*8, rot:Math.random()*Math.PI, vr:(Math.random()-.5)*.3, color:colors[(Math.random()*colors.length)|0] }));
  let frame=0;
  (function tick(){
    ctx.clearRect(0,0,canvas.width,canvas.height); frame++; let alive=false;
    for(const p of pieces){ p.vy+=p.g; p.x+=p.vx; p.y+=p.vy; p.rot+=p.vr; p.vx*=.99; if(p.y<innerHeight+40)alive=true;
      ctx.save(); ctx.translate(p.x,p.y); ctx.rotate(p.rot); ctx.globalAlpha=Math.max(0,1-frame/160); ctx.fillStyle=p.color; ctx.fillRect(-p.size/2,-p.size/2,p.size,p.size*.6); ctx.restore(); }
    if(alive&&frame<160) requestAnimationFrame(tick); else { ctx.clearRect(0,0,canvas.width,canvas.height); canvas.style.display="none"; }
  })();
}

function initVoter(){
  renderShowcase();
  $("#voteNow").addEventListener("click",startVote);
  $("#emailContinue").addEventListener("click",continueFromEmail);
  $("#emailInput").addEventListener("keydown",e=>{ if(e.key==="Enter") continueFromEmail(); });
  $("#submitVote").addEventListener("click",submitVote);
  $$("[data-nav]").forEach(el=>el.addEventListener("click",e=>{ e.preventDefault(); showScreen(el.getAttribute("data-nav")); }));
}

/* ---------- admin page ---------- */
async function adminEnter(){
  const err=$("#adminError"); err.textContent="";
  const pass=$("#adminPass").value;
  try{
    const r=await fetch("/api/admin/results",{ method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({password:pass}) });
    const d=await r.json().catch(()=>({}));
    if(r.ok){ adminPassword=pass; $("#adminLogin").classList.add("hidden"); $("#adminDash").classList.remove("hidden"); renderResults(d); }
    else { err.textContent=d.error||"Incorrect password."; }
  }catch(_){ err.textContent="Could not reach the server."; }
}
async function refreshResults(){
  try{
    const r=await fetch("/api/admin/results",{ method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({password:adminPassword}) });
    if(r.ok) renderResults(await r.json());
  }catch(_){ /* ignore */ }
}
function adminLogout(){ adminPassword=""; $("#adminPass").value=""; $("#adminDash").classList.add("hidden"); $("#adminLogin").classList.remove("hidden"); }

function renderResults(data){
  $("#totalVoters").textContent=data.totalVoters;
  const byId={}; CANDIDATES.forEach(c=>byId[c.id]=c);
  $("#resultsList").innerHTML=data.candidates.map(c=>{
    const yes=data.counts[c.id]?.yes||0, no=data.counts[c.id]?.no||0, t=yes+no, yp=t?Math.round(yes/t*100):0, np=t?100-yp:0;
    const img=IMAGES[c.id];
    return `<div class="result">
      <div class="result__pic" style="${isReal(img)?`background-image:url('${img}')`:""}"></div>
      <div class="result__body">
        <div class="result__head"><span class="result__name">${c.name}</span><span class="result__role">${c.role}</span></div>
        <div class="result__bar">
          <div class="result__seg result__seg--yes" style="flex-basis:${t?yp:50}%">${yes?"Yes "+yp+"%":""}</div>
          <div class="result__seg result__seg--no" style="flex-basis:${t?np:50}%">${no?"No "+np+"%":""}</div>
        </div>
        <div class="result__nums"><span>Yes <b>${yes}</b></span><span>No <b>${no}</b></span></div>
      </div></div>`;
  }).join("");
}

function initAdmin(){
  $("#adminEnter").addEventListener("click",adminEnter);
  $("#adminPass").addEventListener("keydown",e=>{ if(e.key==="Enter") adminEnter(); });
  $("#refreshResults").addEventListener("click",refreshResults);
  $("#adminLogout").addEventListener("click",adminLogout);
}

/* ---------- boot ---------- */
document.addEventListener("DOMContentLoaded",()=>{
  const y=$("#year"); if(y) y.textContent=new Date().getFullYear();
  applyBranding(); startBokeh();
  if($("#showcase")) initVoter();   // voter page
  if($("#adminDash")) initAdmin();  // admin page
});
